    /**
     * Tests methods of \horstoeko\invoicesuite\documents\models\ubl\cac\ActivityDataLineType.
     */
    public function testModelsUblCacActivityDataLineType(): void
    {
        $model = new ActivityDataLineType();

        $this->assertInstanceOf(ActivityDataLineType::class, $model);

        // Property ID

        $testValue = new ID();
        $model->setID($testValue);

        $this->assertEquals($testValue, $model->getID());

        $model->unsetID();

        $this->assertNull($model->getID());

        $testValueForID = $model->getIDWithCreate();

        $this->assertInstanceOf(ID::class, $testValueForID);
        $this->assertSame($testValueForID, $model->getID());

        // Property SupplyChainActivityTypeCode

        $testValue = new SupplyChainActivityTypeCode();
        $model->setSupplyChainActivityTypeCode($testValue);

        $this->assertEquals($testValue, $model->getSupplyChainActivityTypeCode());

        $model->unsetSupplyChainActivityTypeCode();

        $this->assertNull($model->getSupplyChainActivityTypeCode());

        $testValueForSupplyChainActivityTypeCode = $model->getSupplyChainActivityTypeCodeWithCreate();

        $this->assertInstanceOf(SupplyChainActivityTypeCode::class, $testValueForSupplyChainActivityTypeCode);
        $this->assertSame($testValueForSupplyChainActivityTypeCode, $model->getSupplyChainActivityTypeCode());

        // Property BuyerCustomerParty

        $testValue = new BuyerCustomerParty();
        $model->setBuyerCustomerParty($testValue);

        $this->assertEquals($testValue, $model->getBuyerCustomerParty());

        $model->unsetBuyerCustomerParty();

        $this->assertNull($model->getBuyerCustomerParty());

        $testValueForBuyerCustomerParty = $model->getBuyerCustomerPartyWithCreate();

        $this->assertInstanceOf(BuyerCustomerParty::class, $testValueForBuyerCustomerParty);
        $this->assertSame($testValueForBuyerCustomerParty, $model->getBuyerCustomerParty());

        // Property SellerSupplierParty

        $testValue = new SellerSupplierParty();
        $model->setSellerSupplierParty($testValue);

        $this->assertEquals($testValue, $model->getSellerSupplierParty());

        $model->unsetSellerSupplierParty();

        $this->assertNull($model->getSellerSupplierParty());

        $testValueForSellerSupplierParty = $model->getSellerSupplierPartyWithCreate();

        $this->assertInstanceOf(SellerSupplierParty::class, $testValueForSellerSupplierParty);
        $this->assertSame($testValueForSellerSupplierParty, $model->getSellerSupplierParty());

        // Property ActivityPeriod

        $testValue = new ActivityPeriod();
        $model->setActivityPeriod($testValue);

        $this->assertEquals($testValue, $model->getActivityPeriod());

        $model->unsetActivityPeriod();

        $this->assertNull($model->getActivityPeriod());

        $testValueForActivityPeriod = $model->getActivityPeriodWithCreate();

        $this->assertInstanceOf(ActivityPeriod::class, $testValueForActivityPeriod);
        $this->assertSame($testValueForActivityPeriod, $model->getActivityPeriod());

        // Property ActivityOriginLocation

        $testValue = new ActivityOriginLocation();
        $model->setActivityOriginLocation($testValue);

        $this->assertEquals($testValue, $model->getActivityOriginLocation());

        $model->unsetActivityOriginLocation();

        $this->assertNull($model->getActivityOriginLocation());

        $testValueForActivityOriginLocation = $model->getActivityOriginLocationWithCreate();

        $this->assertInstanceOf(ActivityOriginLocation::class, $testValueForActivityOriginLocation);
        $this->assertSame($testValueForActivityOriginLocation, $model->getActivityOriginLocation());

        // Property ActivityFinalLocation

        $testValue = new ActivityFinalLocation();
        $model->setActivityFinalLocation($testValue);

        $this->assertEquals($testValue, $model->getActivityFinalLocation());

        $model->unsetActivityFinalLocation();

        $this->assertNull($model->getActivityFinalLocation());

        $testValueForActivityFinalLocation = $model->getActivityFinalLocationWithCreate();

        $this->assertInstanceOf(ActivityFinalLocation::class, $testValueForActivityFinalLocation);
        $this->assertSame($testValueForActivityFinalLocation, $model->getActivityFinalLocation());

        // (1) Property SalesItem - Test set empty array

        $salesItemItems = [];
        $model->setSalesItem($salesItemItems);

        $this->assertIsArray($model->getSalesItem());
        $this->assertCount(0, $model->getSalesItem());

        // (2) Property SalesItem - Add instance

        $salesItemItem = new SalesItem();
        $model->addToSalesItem($salesItemItem);

        $this->assertIsArray($model->getSalesItem());
        $this->assertCount(1, $model->getSalesItem());

        // (3) Property SalesItem - Add and create instancc

        $testValueForSalesItemItem = $model->addToSalesItemWithCreate();

        $this->assertInstanceOf(SalesItem::class, $testValueForSalesItemItem);
        $this->assertIsArray($model->getSalesItem());
        $this->assertCount(2, $model->getSalesItem());

        // (4) Property SalesItem - Add once an instance

        $salesItemOnceItem = new SalesItem();

        $model->addOnceToSalesItem($salesItemOnceItem);
        $model->addOnceToSalesItem($salesItemOnceItem);

        $itemsAfterOnce = $model->getSalesItem();

        $this->assertIsArray($itemsAfterOnce);
        $this->assertCount(2, $itemsAfterOnce);

        // (5) Property SalesItem - Add once an instance with implicit creation

        $firstSalesItemOnceItem = $model->addOnceToSalesItemWithCreate();

        $this->assertInstanceOf(SalesItem::class, $firstSalesItemOnceItem);

        $itemsAfterFirstOnceWithCreate = $model->getSalesItem();

        $this->assertIsArray($itemsAfterFirstOnceWithCreate);
        $this->assertCount(2, $itemsAfterFirstOnceWithCreate);

        // (5) Property SalesItem - Add once an instance with implicit creation (2)

        $secondSalesItemOnceItem = $model->addOnceToSalesItemWithCreate();

        $this->assertIsArray($itemsAfterFirstOnceWithCreate);
        $this->assertCount(2, $itemsAfterFirstOnceWithCreate);
        $this->assertSame($firstSalesItemOnceItem, $secondSalesItemOnceItem);

        $firstSalesItem = $model->firstSalesItem();

        $this->assertInstanceOf(SalesItem::class, $firstSalesItem);

        $lastSalesItem = $model->lastSalesItem();

        $this->assertInstanceOf(SalesItem::class, $lastSalesItem);

        // (7) Property SalesItem - Clesr

        $model->clearSalesItem();

        $itemsAfterClear = $model->getSalesItem();

        $this->assertIsArray($itemsAfterClear);
        $this->assertCount(0, $itemsAfterClear);
    }

